Here is a C++ implementation for the described problem. This implementation follows the structured approach of constructing the graph, calculating the shortest paths using Dijkstra's algorithm, and then identifying which fiber connections are redundant based on the shortest path distances calculated.

```cpp
#include <iostream>
#include <vector>
#include <queue>
#include <limits>
#include <unordered_map>

using namespace std;

const long long INF = numeric_limits<long long>::max();

struct Edge {
    int to;
    long long weight;
    Edge(int to, long long weight) : to(to), weight(weight) {}
};

void dijkstra(int source, const vector<vector<Edge>>& graph, vector<long long>& distances) {
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    distances.assign(graph.size(), INF);
    distances[source] = 0;
    pq.push({0, source});

    while (!pq.empty()) {
        auto [dist, u] = pq.top();
        pq.pop();

        if (dist > distances[u]) continue;

        for (const auto& edge : graph[u]) {
            int v = edge.to;
            long long weight = edge.weight;

            if (distances[u] + weight < distances[v]) {
                distances[v] = distances[u] + weight;
                pq.push({distances[v], v});
            }
        }
    }
}

int main() {
    int n, m, k;
    cin >> n >> m >> k;

    vector<vector<Edge>> graph(n + 1);
    unordered_map<int, long long> fiberConnections;

    // Read normal connections
    for (int i = 0; i < m; ++i) {
        int from, to;
        long long weight;
        cin >> from >> to >> weight;
        graph[from].emplace_back(to, weight);
        graph[to].emplace_back(from, weight);
    }

    // Read fiber connections
    for (int i = 0; i < k; ++i) {
        int ci;
        long long pi;
        cin >> ci >> pi;
        fiberConnections[ci] = pi;
        // Add fiber connection to the graph for the shortest path calculation
        graph[1].emplace_back(ci, pi);
        graph[ci].emplace_back(1, pi);
    }

    // Calculate shortest paths from HQ (1) to all nodes
    vector<long long> distances;
    dijkstra(1, graph, distances);

    // Count removable fiber connections
    int removableFibers = 0;
    for (const auto& [ci, pi] : fiberConnections) {
        if (distances[ci] <= pi) {
            removableFibers++;
        }
    }

    cout << removableFibers << endl;

    return 0;
}
```

This program first reads the input graph, including both normal and fiber connections, constructs the graph data structure (`graph`) using adjacency lists where each list consists of `Edge` objects encapsulating destination nodes and edge weights. It then uses Dijkstra's algorithm to find the shortest paths from the HQ (office 1) to all other offices. Finally, the program checks each fiber connection against the recorded shortest paths: if the distance via the fiber connection does not offer any improvement over the calculated shortest path, it's considered removable.

Please note, for extremely large inputs, the efficiency of Dijkstra's algorithm could become a bottleneck due to its \(\mathcal{O}((V+E) \log V)\) complexity, where \(V\) is the number of vertices and \(E\) is the number of edges. In practical use cases where performance issues are observed, further optimizations like using a Fibonacci heap (which can decrease the complexity) or applying a different algorithm suited for specific graph characteristics might be necessary.

